SELECT COUNT(*) AS TOTAL FROM LATTES_P_PRODTEC PP JOIN LATTES_PRODTEC PT ON PT.PK = PP.FK_PRODTEC JOIN SERVIDOR S ON S.PK_SIAPE = PP.FK_SIAPE WHERE LOWER(S.GENERO) = LOWER('masculino') AND S.SIGLA_CAMPUS = 'ITU' AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%matem%' AND PT.ANO >= (CAST(strftime('%Y', 'now') AS INTEGER) - 4) AND LOWER(COALESCE(PT.NATUREZA, '')) LIKE '%organiz%'